module d_latch (
  input D,
  input EN,
  input RST,
  output Q
);

  reg Q_reg;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge EN or posedge dbg_halt) begin
    if (RST) begin
      Q_reg <= 1'b0;
    end else begin
      Q_reg <= D;
    end
  end

  assign Q = Q_reg;

endmodule
